// ─── Signature Pad Component ─────────────────────────────────────────────────
function SigPad({ label, onSigned, signed }) {
  const canvasRef = { current: null };
  const sigRef = (el) => { canvasRef.current = el; };
  const [hasSig, setHasSig] = useState(false);
  const [name, setName] = useState('');
  const drawing = { current: false };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const resize = () => {
      const rect = canvas.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      ctx.scale(dpr, dpr);
      ctx.strokeStyle = '#C9A87A';
      ctx.lineWidth = 2.5;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
    };
    resize();
    const getPos = (e) => {
      const rect = canvas.getBoundingClientRect();
      const src = e.touches ? e.touches[0] : e;
      return { x: src.clientX - rect.left, y: src.clientY - rect.top };
    };
    const start = (e) => { e.preventDefault(); drawing.current = true; const { x, y } = getPos(e); ctx.beginPath(); ctx.moveTo(x, y); };
    const move  = (e) => { e.preventDefault(); if (!drawing.current) return; const { x, y } = getPos(e); ctx.lineTo(x, y); ctx.stroke(); setHasSig(true); };
    const end   = () => { drawing.current = false; };
    canvas.addEventListener('mousedown', start);
    canvas.addEventListener('mousemove', move);
    canvas.addEventListener('mouseup', end);
    canvas.addEventListener('touchstart', start, { passive: false });
    canvas.addEventListener('touchmove', move, { passive: false });
    canvas.addEventListener('touchend', end);
    window.addEventListener('resize', resize);
    return () => {
      canvas.removeEventListener('mousedown', start);
      canvas.removeEventListener('mousemove', move);
      canvas.removeEventListener('mouseup', end);
      canvas.removeEventListener('touchstart', start);
      canvas.removeEventListener('touchmove', move);
      canvas.removeEventListener('touchend', end);
      window.removeEventListener('resize', resize);
    };
  }, []);

  const clearSig = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    canvas.getContext('2d').clearRect(0, 0, canvas.width, canvas.height);
    setHasSig(false);
  };

  const canConfirm = hasSig && name.trim().length > 2 && !signed;

  if (signed) {
    return (
      <div className="sig-wrap" style={{borderColor:'rgba(58,182,211,0.4)', background:'rgba(58,182,211,0.05)'}}>
        <div style={{display:'flex', alignItems:'center', gap:'10px'}}>
          <span style={{color:'var(--cyan)', fontSize:'20px'}}>✓</span>
          <span style={{fontFamily:'Oswald, sans-serif', fontSize:'13px', letterSpacing:'0.1em', textTransform:'uppercase', color:'var(--cyan)'}}>{label} Signed</span>
        </div>
      </div>
    );
  }

  return (
    <div className="sig-wrap">
      <span className="sig-label">{label} - Draw Your Signature</span>
      <canvas ref={sigRef} className={`sig-canvas ${hasSig ? 'has-sig' : ''}`} />
      <button className="sig-clear" onClick={clearSig}>Clear</button>
      <input
        className="sig-name-input"
        placeholder="Type your full name to confirm"
        value={name}
        onChange={e => setName(e.target.value)}
      />
      <button
        className="btn-primary"
        style={{marginTop:'16px', opacity: canConfirm ? 1 : 0.4, cursor: canConfirm ? 'pointer' : 'not-allowed'}}
        onClick={() => canConfirm && onSigned(name)}
      >
        Confirm Signature
      </button>
    </div>
  );
}

