// ─── Email Notification via Vercel API Route ─────────────────────────────────
async function sendCompletionEmail({ clientName, retainer, proposalSignedAt, contractSignedAt, paymentAmount }) {
  try {
    const res = await fetch('/api/send-email', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ clientName, retainer, proposalSignedAt, contractSignedAt, paymentAmount }),
    });
    const data = await res.json();
    if (res.ok) {
      console.log('Email sent successfully');
    } else {
      console.error('Email error:', data);
    }
  } catch (err) {
    console.error('Email failed:', err);
  }
}


