function openPDF(data) {
  const html = generatePDFContent(data);
  const win = window.open('', '_blank');
  win.document.write(html);
  win.document.close();
  setTimeout(() => win.print(), 500);
}

// ─── App ──────────────────────────────────────────────────────────────────────
export default function App() {
  const [step, setStep] = useState(1);
  const [signedData, setSignedData] = useState(null);
  const [proposalSigName, setProposalSigName] = useState('');
  const [proposalSignedAt, setProposalSignedAt] = useState('');
  const [contractSignedAt, setContractSignedAt] = useState('');


  // steps: 1=proposal view, 2=proposal sig, 3=contract sig, 4=payment, 5=thankyou
  const progressStep = step <= 1 ? 1 : step <= 3 ? 2 : step === 4 ? 3 : 4;

  const steps = [
    { num: 1, label: 'Proposal' },
    { num: 2, label: 'Agreement' },
    { num: 3, label: 'Payment' },
  ];

  return (
    <>
      <style>{styles}</style>

      {step < 5 && (
        <div className="progress-wrap">
          <div className="progress-steps">
            {steps.map((s, i) => (
              <div key={s.num} className={`step-item ${progressStep === s.num ? 'active' : progressStep > s.num ? 'done' : ''}`}>
                <div className="step-num">{progressStep > s.num ? '✓' : s.num}</div>
                <span className="step-label">{s.label}</span>
                {i < steps.length - 1 && <div style={{flex:1, height:'1px', background:'var(--border)', margin:'0 8px'}} />}
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="app">
        {step === 1 && <StepProposal onAccept={() => setStep(2)} />}
        {step === 2 && <StepSignProposal onSigned={(name) => {
          setProposalSigName(name);
          setProposalSignedAt(new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' }));
          setStep(3);
        }} />}
        {step === 3 && <StepSignContract proposalName={proposalSigName} onSign={(data) => {
          setSignedData(data);
          setContractSignedAt(new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' }));
          setStep(4);
        }} />}
        {step === 4 && <StepPayment signedData={signedData} onPaid={() => {
          const pdfData = {
            clientName: proposalSigName,
            retainer: signedData?.retainer || 'none',
            proposalSignedAt,
            contractSignedAt,
          };
          sendCompletionEmail({
            clientName: proposalSigName,
            retainer: signedData?.retainer || 'none',
            proposalSignedAt,
            contractSignedAt,
            paymentAmount: '500.00',
          });
          openPDF(pdfData);
          setStep(5);
        }} />}
        {step === 5 && <ThankYou clientName={proposalSigName} />}
      </div>
    </>
  );
}
